import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Play, Pause, Square, Settings, ChevronUp, ChevronDown } from 'lucide-react';
import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';
import { useTimeTrackingPanelStore } from '../stores/useTimeTrackingPanelStore';
import { formatDuration, formatTime } from '../utils/timeFormatters';
import type { TimeEntry } from '../types';

/**
 * TimeTrackingPanel Component
 * Persistent timer panel in the sidebar (Toggl-style)
 * Fixed bottom position, shows active timer + recent entries
 */
export function TimeTrackingPanel() {
  const navigate = useNavigate();

  // Panel settings
  const {
    panelHeight,
    visibleEntries,
    showMiniSummary,
    entryDisplayDensity,
    timeFormat,
    showSeconds,
    isPanelCollapsed,
    togglePanelCollapsed,
  } = useTimeTrackingPanelStore();

  // Time tracking state
  const store = useTimeTrackingStore();
  const {
    activeEntry,
    entries,
    startTimer,
    stopTimer,
    pauseTimer,
    resumeTimer,
    updateTimerDescription,
    getRecentEntries,
    getTodayTotal,
    isTimerRunning,
    timerDescription,
    timerProjectId,
  } = store;

  // Call getter methods
  const isRunning = isTimerRunning();
  const currentDescription = timerDescription();
  const currentProjectId = timerProjectId();

  // Local state
  const [currentTime, setCurrentTime] = useState<number>(0);
  const [recentEntries, setRecentEntries] = useState<TimeEntry[]>([]);
  const [todayTotal, setTodayTotal] = useState<number>(0);
  const [description, setDescription] = useState(currentDescription || '');

  // Resize drag state
  const [isDragging, setIsDragging] = useState(false);
  const [dragStartY, setDragStartY] = useState(0);
  const [dragStartHeight, setDragStartHeight] = useState(panelHeight);

  // Update current time every second when timer is running
  useEffect(() => {
    if (!activeEntry?.startTime) {
      setCurrentTime(0);
      return;
    }

    const updateTime = () => {
      const start = new Date(activeEntry.startTime!).getTime();
      const now = Date.now();
      const elapsed = Math.floor((now - start) / 1000); // seconds
      setCurrentTime(elapsed);
    };

    updateTime(); // Initial update

    // Only set interval if timer is actively running (not paused)
    if (isRunning) {
      const interval = setInterval(updateTime, 1000);
      return () => clearInterval(interval);
    }
  }, [isRunning, activeEntry]);

  // Load recent entries and today's total
  useEffect(() => {
    const loadData = async () => {
      // Get entries from last 48 hours
      const recentEntries = await getRecentEntries(48);
      setRecentEntries(recentEntries.slice(0, visibleEntries)); // Limit to visible count

      // Get today's total
      const total = await getTodayTotal();
      setTodayTotal(total);
    };

    loadData();

    // Refresh every 60 seconds
    const interval = setInterval(loadData, 60000);
    return () => clearInterval(interval);
  }, [entries, visibleEntries, getRecentEntries, getTodayTotal]);

  // Sync description with timer
  useEffect(() => {
    setDescription(currentDescription || '');
  }, [currentDescription]);

  // Handlers
  const handleStartTimer = () => {
    startTimer({
      description: description || 'Untitled Task',
      projectId: currentProjectId || undefined,
    });
  };

  const handleStopTimer = async () => {
    await stopTimer();
    setDescription(''); // Clear description after stopping
  };

  const handlePauseTimer = () => {
    pauseTimer();
  };

  const handleResumeTimer = () => {
    resumeTimer();
  };

  const handleDescriptionChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newDescription = e.target.value;
    setDescription(newDescription);
    if (isRunning) {
      updateTimerDescription(newDescription);
    }
  };

  const handleViewAll = () => {
    navigate('/time-tracking');
  };

  const handleContinueEntry = (entry: TimeEntry) => {
    setDescription(entry.description);
    startTimer({
      description: entry.description,
      projectId: entry.projectId,
    });
  };

  // Resize drag handlers
  const handleDragStart = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStartY(e.clientY);
    setDragStartHeight(panelHeight);
    e.preventDefault();
  };

  // Attach global mouse move and mouseup listeners when dragging
  useEffect(() => {
    if (!isDragging) return;

    const handleDragMove = (e: MouseEvent) => {
      // Calculate the change in Y position (negative because dragging up expands)
      const deltaY = dragStartY - e.clientY;

      // More responsive calculation: 5px mouse movement = ~1% height change
      const heightChange = deltaY / 5;
      const newHeight = dragStartHeight + heightChange;

      // Use store's setter which handles validation (20-50% range)
      useTimeTrackingPanelStore.getState().setPanelHeight(newHeight);
    };

    const handleDragEnd = () => {
      setIsDragging(false);
    };

    window.addEventListener('mousemove', handleDragMove);
    window.addEventListener('mouseup', handleDragEnd);

    return () => {
      window.removeEventListener('mousemove', handleDragMove);
      window.removeEventListener('mouseup', handleDragEnd);
    };
  }, [isDragging, dragStartY, dragStartHeight]);

  // Calculate panel height in pixels (percentage of sidebar)
  const panelStyle = {
    height: isPanelCollapsed ? 'auto' : `${panelHeight}%`,
    minHeight: isPanelCollapsed ? 'auto' : '200px',
    maxHeight: isPanelCollapsed ? 'auto' : '400px',
  };

  // Get density-based spacing
  const getDensityClasses = () => {
    switch (entryDisplayDensity) {
      case 'compact':
        return 'py-1 text-xs';
      case 'comfortable':
        return 'py-3 text-sm';
      default:
        return 'py-2 text-sm';
    }
  };

  return (
    <div
      className="border-t border-light-divider dark:border-dark-divider bg-light-surface dark:bg-dark-surface flex flex-col transition-all duration-200"
      style={panelStyle}
    >
      {/* Drag Handle - Only visible when not collapsed */}
      {!isPanelCollapsed && (
        <div
          onMouseDown={handleDragStart}
          className="h-4 cursor-ns-resize hover:bg-accent-magenta/10 dark:hover:bg-accent-cyan/10 transition-colors flex items-center justify-center group"
          title="Drag to resize panel"
        >
          <div className="w-full h-0.5 bg-light-divider dark:bg-dark-divider rounded group-hover:bg-accent-magenta dark:group-hover:bg-accent-cyan transition-colors" />
        </div>
      )}

      {/* Panel Header */}
      <div className="flex items-center justify-between px-3 py-1 border-b border-light-divider dark:border-dark-divider">
        <div className="flex items-center gap-2">
          <span className="text-lg">âڈ±ï¸ڈ</span>
          <h3 className="text-sm font-semibold text-light-primary dark:text-dark-primary">
            Time Tracking
          </h3>
        </div>
        <div className="flex items-center gap-1">
          <button
            onClick={togglePanelCollapsed}
            className="p-1 rounded hover:bg-light-hover dark:hover:bg-dark-hover text-light-secondary dark:text-dark-secondary transition-colors"
            aria-label={isPanelCollapsed ? 'Expand panel' : 'Collapse panel'}
          >
            {isPanelCollapsed ? (
              <ChevronUp className="w-4 h-4" />
            ) : (
              <ChevronDown className="w-4 h-4" />
            )}
          </button>
          <button
            onClick={() => navigate('/settings?tab=time-tracking')}
            className="p-1 rounded hover:bg-light-hover dark:hover:bg-dark-hover text-light-secondary dark:text-dark-secondary transition-colors"
            aria-label="Time tracking settings"
          >
            <Settings className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Panel Content (hidden when collapsed) */}
      {!isPanelCollapsed && (
        <>
          {/* Active Timer Section */}
          <div className="px-3 py-3 border-b border-light-divider dark:border-dark-divider">
            {/* Timer Display - Show whenever there's an active entry */}
            {activeEntry && (
              <div className="mb-2 text-center">
                <div className="text-2xl font-mono font-bold text-accent-magenta dark:text-accent-cyan">
                  {formatDuration(currentTime, { showSeconds })}
                </div>
                {activeEntry.isPaused && (
                  <div className="text-xs text-status-warning font-medium mt-1">
                    Paused
                  </div>
                )}
              </div>
            )}

            {/* Description Input */}
            <input
              type="text"
              value={description}
              onChange={handleDescriptionChange}
              placeholder="What are you working on?"
              className="w-full px-3 py-2 mb-2 text-sm bg-light-surface dark:bg-dark-surface border border-light-divider dark:border-dark-divider rounded focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-light-primary dark:text-dark-primary placeholder-light-tertiary dark:placeholder-dark-tertiary"
            />

            {/* Project Selector (TODO: Implement in Phase 2) */}
            <div className="mb-3">
              <select
                className="w-full px-3 py-2 text-sm bg-light-background dark:bg-dark-background border border-light-divider dark:border-dark-divider rounded focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-light-primary dark:text-dark-primary"
                disabled
              >
                <option>ًں“پ Select Project</option>
              </select>
            </div>

            {/* Timer Controls */}
            <div className="flex items-center gap-2">
              {!activeEntry ? (
                <button
                  onClick={handleStartTimer}
                  className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-accent-magenta dark:bg-accent-cyan text-white dark:text-dark-background rounded font-medium hover:opacity-90 transition-opacity"
                >
                  <Play className="w-4 h-4" />
                  Start Timer
                </button>
              ) : (
                <>
                  <button
                    onClick={activeEntry?.isPaused ? handleResumeTimer : handlePauseTimer}
                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-status-warning text-white rounded font-medium hover:opacity-90 transition-opacity"
                  >
                    {activeEntry?.isPaused ? (
                      <>
                        <Play className="w-4 h-4" />
                        Resume
                      </>
                    ) : (
                      <>
                        <Pause className="w-4 h-4" />
                        Pause
                      </>
                    )}
                  </button>
                  <button
                    onClick={handleStopTimer}
                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-status-error text-white rounded font-medium hover:opacity-90 transition-opacity"
                  >
                    <Square className="w-4 h-4" />
                    Stop
                  </button>
                </>
              )}
            </div>
          </div>

          {/* Recent Entries List */}
          <div className="flex-1 overflow-y-auto px-3 py-2">
            <h4 className="text-xs font-semibold text-light-secondary dark:text-dark-secondary mb-2">
              Recent Entries (Last 48h)
            </h4>
            {recentEntries.length === 0 ? (
              <p className="text-xs text-light-tertiary dark:text-dark-tertiary italic">
                No entries yet. Start your first timer!
              </p>
            ) : (
              <div className="space-y-1">
                {recentEntries.map((entry) => (
                  <div
                    key={entry.id}
                    className={`${getDensityClasses()} px-2 rounded hover:bg-light-hover dark:hover:bg-dark-hover cursor-pointer transition-colors`}
                    onClick={() => handleContinueEntry(entry)}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex-1 min-w-0">
                        <p className="text-light-primary dark:text-dark-primary truncate font-medium">
                          {entry.description}
                        </p>
                        <div className="flex items-center gap-2 text-xs text-light-secondary dark:text-dark-secondary">
                          <span>
                            {formatTime(new Date(entry.startTime), timeFormat)}
                          </span>
                          {entry.endTime && (
                            <>
                              <span>-</span>
                              <span>
                                {formatTime(new Date(entry.endTime), timeFormat)}
                              </span>
                            </>
                          )}
                          <span className="font-medium">
                            ({formatDuration(entry.duration, { showSeconds: false })})
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Mini Summary & View All Button */}
          {showMiniSummary && (
            <div className="px-3 py-3 border-t border-light-divider dark:border-dark-divider">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-semibold text-light-secondary dark:text-dark-secondary">
                  Today's Total:
                </span>
                <span className="text-sm font-mono font-bold text-accent-magenta dark:text-accent-cyan">
                  {formatDuration(todayTotal, { showSeconds: false })}
                </span>
              </div>
              <button
                onClick={handleViewAll}
                className="w-full px-3 py-2 text-sm bg-light-background dark:bg-dark-background border border-light-divider dark:border-dark-divider rounded hover:bg-light-hover dark:hover:bg-dark-hover text-light-primary dark:text-dark-primary font-medium transition-colors"
              >
                View All â†’
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

